using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithId(".NET 9").AsBaseline())
    .AddJob(Job.Default.WithId(".NET 10"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config, args);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // Build a realistic text with ~1000 words
        var words = new string[]
        {
            "the", "quick", "brown", "fox", "jumps", "over", "lazy", "dog",
            "performance", "benchmarking", "is", "important", "for", "measuring",
            "improvements", "across", "different", "runtime", "versions", "of",
            "dotnet", "framework", "applications", "and", "libraries", "that",
            "process", "text", "data", "efficiently", "in", "production",
            "environments", "with", "high", "throughput", "requirements"
        };
        var rng = new Random(42);
        var parts = new string[1000];
        for (int i = 0; i < parts.Length; i++)
            parts[i] = words[rng.Next(words.Length)];

        _analyzer = new TextAnalyzer(string.Join(' ', parts));
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

